VALUES
  ('optician-moex-00589', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於自覺驗光使用之紅綠雙色檢查法（duochrometest）之原理，下列敘述何者錯誤？', '["是利用色相差之原理來設計此一檢查項目", "紅色波長較長，會落在視網膜後", "綠色波長較短，會落在視網膜前", "若患者表示紅色之視標較綠色清楚，則表示影像較偏向視網膜前，需增加+0.25D之度數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00590', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '利用時鐘刻度表示的散光圖形表，在適當的霧視後，受檢者指出三點鐘到四點鐘中間的線條最明顯，顏色 最深。以負圓柱透鏡矯正時，矯正軸度應放置於：', '["45度", "75度", "105度", "165度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00591', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '己知受驗者的遠點在無限遠而近點在20cm，則其調節幅度為：', '["6D", "5D", "4D", "3D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00592', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關進行傑克森交叉圓柱鏡（Jacksoncrosscylinder,JCCtest）測試，下列敘述何者最適當？', '["標示比受測者單眼自覺式驗光的最佳視力小一行的視標", "通常先確認散光軸度再確認散光度數，除非電腦驗光散光不超過0.50D", "先進行JCC測試再測單眼最大正球面度最佳視力（maximumplustomaximumvisualacuity,MPMVA）的 球面度數", "如果JCC散光結果和初始相差1D，只要重新確認散光度數即可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00593', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於裂孔板驗光（stenopaicslitrefraction）的敘述，下列何者錯誤？', '["和針孔視力一樣，裂孔板也可以當作確認視力潛在能力的測量", "對視力不良或不規則散光是有效的再確認測量", "設置整面視標，讓最佳視力剛好在最下排", "旋轉裂孔板找到最佳視力，裂孔垂直於處方的負圓柱鏡軸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00594', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用裂孔板驗光的敘述，下列何者最為正確？', '["裂孔板驗光是用以決定最佳球面度的方法", "使用裂孔板驗光前，需先找最佳球面度，然後再霧視，使最小模糊圈落於視網膜前", "使用裂孔板驗光，不需先找最佳球面度，直接旋轉裂孔板尋找最佳視力時的裂孔縫線位置", "使用裂孔板驗光前，需先找最佳球面度，不可霧視，保持最小模糊圈落於視網膜上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00595', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列何者不是採用試鏡框驗光（trialframerefraction）的優點？', '["檢者可調整頂點距離（vertexdistance）與前傾角（pantoscopictilt）以類似實際配戴眼鏡框", "有助確定斜頸者（torticollis）的屈光異常度數", "提供被檢者戴試鏡框自由的望出窗外和走動以更確定屈光異常度數", "被檢者的調節與聚散系統發現值在綜合驗光儀（phoropter）的處方比試鏡框的處方更具真實體驗（realistic experience）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00596', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者起始度數為+1.00DS/-1.50DC×180，進行傑克森交叉圓柱鏡散光度確認時，連續兩次修正度數都表 達為紅點較清楚，此時度數應改變為：', '["+0.75DS/-2.00DC×180", "+0.75DS/-1.00DC×180", "+1.25DS/-2.00DC×180", "+1.25DS/-1.00DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00597', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以交叉圓柱鏡檢查法檢查散光的度數，檢測時當白點位置在散光軸180度患者反應清楚，則檢查者應如何處置？', '["散光軸在90度，散光度數增加-0.25D", "散光軸在180度，散光度數增加-0.25D", "散光軸在180度，散光度數減少-0.25D", "不必變動散光度數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00598', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '角膜地形圖儀（cornealtopography）利用普拉希多盤（Placido’sdisc）照射在角膜前端部位，所反射的光是 下列浦肯頁影像（Purkinjeimage）的那一種？', '["浦肯頁影像（Purkinjeimage）I", "浦肯頁影像（Purkinjeimage）Ⅱ", "浦肯頁影像（Purkinjeimage）Ⅲ", "浦肯頁影像（Purkinjeimage）Ⅳ"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
